    # Check if the file name has precisely one period
    if file_name.count('.') != 1:
        return 'No'

    # Split the file name into name and extension
    name, extension = file_name.split('.')

    # Check if the name is not empty and starts with a latin letter
    if not name or not name[0].isalpha():
        return 'No'

    # Check if the extension is one of the allowed ones
    if extension not in {'txt', 'exe', 'dll'}:
        return 'No'

    # Check if the file name contains at most three numeric characters
    if len(re.findall(r'\d', file_name)) > 3:
        return 'No'

